package com.naenae.student.assignment.controller;
import com.naenae.common.file.FileDownloadResponseFactory;import com.naenae.common.user.domain.User;import com.naenae.student.assignment.service.StudentAssignmentService;import com.naenae.teacher.assignment.model.AssignmentDownload;import com.naenae.teacher.auth.security.CustomUserDetails;import org.springframework.core.io.Resource;import org.springframework.http.ResponseEntity;import org.springframework.security.core.Authentication;import org.springframework.stereotype.Controller;import org.springframework.ui.Model;import org.springframework.web.bind.annotation.*;
@Controller public class StudentAssignmentController {private final StudentAssignmentService service;private final FileDownloadResponseFactory downloads;public StudentAssignmentController(StudentAssignmentService service,FileDownloadResponseFactory downloads){this.service=service;this.downloads=downloads;}@GetMapping("/student/assignments")public String list(@RequestParam(defaultValue="0")int page,Authentication a,Model m){m.addAttribute("assignmentPage",service.getAssignments(user(a),page));return "student/assignments";}@GetMapping("/student/assignments/{id}")public String detail(@PathVariable Long id,Authentication a,Model m){m.addAttribute("assignment",service.getAssignment(user(a),id));return "student/assignment-detail";}@GetMapping("/student/assignments/{id}/attachments/{fileId}/download")public ResponseEntity<Resource> download(@PathVariable Long id,@PathVariable Long fileId,Authentication a){AssignmentDownload d=service.download(user(a),id,fileId);return downloads.create(d.path(),d.originalName(),d.contentType());}private Long user(Authentication a){if(a!=null&&a.getPrincipal() instanceof CustomUserDetails d){User u=d.getUser();return u.getId();}throw new IllegalStateException("로그인 정보가 없습니다.");}}